def filter_by_score_gap(
    pairs: list[dict],
    min_gap: float = 2.0,
    score_key: str = "score_gap",
) -> tuple[list[dict], list[dict]]:
    """Returns (kept, filtered) pair lists."""
    kept = [p for p in pairs if p.get(score_key, 0) >= min_gap]
    filtered = [p for p in pairs if p.get(score_key, 0) < min_gap]
    return kept, filtered

# For UltraFeedback-style datasets, compute gap first
def enrich_with_gap(pair: dict) -> dict:
    gap = abs(pair.get("chosen_score", 0) - pair.get("rejected_score", 0))
    return {**pair, "score_gap": gap}
